#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10;

int n,m,a[N],ls[N],sa[N],height[N],x[N],y[N],c[N],rk[N],f[N][20],pre[N],nxt[N];
long long ans[N];
map<int,int> mp;

void get_sa(){
    for(int i=1;i<=n;i++) c[x[i]=mp[a[i]]]++;
    for(int i=2;i<=m;i++) c[i]+=c[i-1];
    for(int i=n;i;i--) sa[c[x[i]]--]=i;
    int num;
    for(int k=1;k<=n;k<<=1){
        num=0;
        for(int i=n-k+1;i<=n;i++) y[++num]=i;
        for(int i=1;i<=n;i++)
            if(sa[i]>k)
                y[++num]=sa[i]-k;
        for(int i=1;i<=m;i++) c[i]=0;
        for(int i=1;i<=n;i++) c[x[i]]++;
        for(int i=2;i<=m;i++) c[i]+=c[i-1];
        for(int i=n;i;i--) sa[c[x[y[i]]]--]=y[i],y[i]=0;
        swap(x,y);
        x[sa[1]]=num=1;
        for(int i=2;i<=n;i++)
            x[sa[i]]=(y[sa[i]]==y[sa[i-1]] && y[sa[i]+k]==y[sa[i-1]+k])?num:++num;
        if(num==n) break;
        m=num;
    }
}

void get_height(){
    for(int i=1;i<=n;i++) rk[sa[i]]=i;
    for(int i=1,k=0;i<=n;i++){
        if(rk[i]==1){
            k=0;
            continue;
        }
        k=max(0,k-1);
        int j=sa[rk[i]-1];
        while(i+k<=n && j+k<=n && a[i+k]==a[j+k]) k++;
        height[rk[i]]=k;
    }
}

int get_min(int l,int r){
    int len=log2(r-l+1);
    return min(f[r][len],f[l+(1<<len)-1][len]);
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        ls[i]=a[i];
    }
    reverse(a+1,a+n+1);
    sort(ls+1,ls+n+1);
    m=unique(ls+1,ls+n+1)-ls-1;
    for(int i=1;i<=m;i++) mp[ls[i]]=i;
    get_sa();
    get_height();
    for(int i=1;i<=n;i++){
        f[i][0]=height[i];
        for(int j=1;(1<<j)<=i;j++)
            f[i][j]=min(f[i][j-1],f[i-(1<<j-1)][j-1]);
    }
    for(int i=1;i<=n;i++){
        pre[i]=i-1;
        nxt[i]=(i+1)%(n+1);
    }
    for(int i=1;i<=n;i++){
        int p=rk[i],len=0;
        if(pre[p]) len=max(len,get_min(pre[p]+1,p));
        if(nxt[p]) len=max(len,get_min(p+1,nxt[p]));
        ans[i]=n-i+1-len;
        if(pre[p]) nxt[pre[p]]=nxt[p];
        if(nxt[p]) pre[nxt[p]]=pre[p];
    }
    for(int i=n;i;i--){
        ans[i]+=ans[i+1];
        printf("%lld\n",ans[i]);
    }
    return 0;
}
